package com.example.sharehandler

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class ShareHandlerActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share_handler)

        handleIncomingShare(intent)
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        handleIncomingShare(intent)
    }

    private fun handleIncomingShare(intent: Intent) {
        if (intent.action == Intent.ACTION_SEND || intent.action == Intent.ACTION_SEND_MULTIPLE) {
            if (intent.type != null) {
                when {
                    intent.type!!.startsWith("text/") -> handleText(intent)
                    intent.type!!.startsWith("image/") -> handleImage(intent)
                }
            }
        }
    }

    private fun handleText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        if (sharedText != null) {
            // Process the shared text URL
            Toast.makeText(this, "Received URL: $sharedText", Toast.LENGTH_SHORT).show()
        }
    }

    private fun handleImage(intent: Intent) {
        val imageUris: List<Uri>? = if (intent.action == Intent.ACTION_SEND) {
            listOf(intent.getParcelableExtra(Intent.EXTRA_STREAM)!!)
        } else {
            intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM)
        }

        imageUris?.let {
            // Process the shared images
            Toast.makeText(this, "Received ${it.size} image(s)", Toast.LENGTH_SHORT).show()
        }
    }
}